#[test]
fn rendered_list_editing_respects_item_indices() {
    let md = "## Header Above List\n\n- First list item\n- Second list item\n- Third list item\n";
    let mut doc = parse_markdown(md);

    // simulate click on each list item
    for (idx, expected) in [
        (0, "First list item"),
        (1, "Second list item"),
        (2, "Third list item"),
    ] {
        let (node_id, path) = map_click_to_ast_node_for_test(idx, &doc).unwrap();
        assert_eq!(extract_list_item_text(node_id, &doc.ast), expected);

        commit_list_item_edit(&path, &format!("{} (edited)", expected), &mut doc);
    }

    let out = render_markdown(&doc.ast);
    assert!(out.contains("First list item (edited)"));
    assert!(out.contains("Second list item (edited)"));
    assert!(out.contains("Third list item (edited)"));
}
```
